"use client";

import Image from "next/image";
import { useEffect, useRef } from "react";
import styles from "./Pokeball.module.css";

const GRAVITY = 3600; // px/s^2
const LAUNCH_V = -950; // px/s, upward
const RESTITUTION = 0.58; // energy kept per bounce
const REST_V = 60; // settle when rebound is slower than this

export default function Pokeball({ size = 48 }: { size?: number }) {
  const ref = useRef<HTMLSpanElement | null>(null);
  const sim = useRef({ y: 0, v: 0, raf: 0, last: 0 });

  useEffect(() => {
    const s = sim.current;
    return () => cancelAnimationFrame(s.raf);
  }, []);

  const step = (now: number) => {
    const s = sim.current;
    const dt = Math.min((now - s.last) / 1000, 0.032);
    s.last = now;
    s.v += GRAVITY * dt;
    s.y += s.v * dt;
    if (s.y >= 0) {
      // hit the floor: rebound with damping
      s.y = 0;
      s.v = -s.v * RESTITUTION;
      if (-s.v < REST_V) {
        s.v = 0;
        s.raf = 0;
        if (ref.current) ref.current.style.transform = "";
        return;
      }
    }
    if (ref.current) ref.current.style.transform = `translateY(${s.y}px)`;
    s.raf = requestAnimationFrame(step);
  };

  const launch = () => {
    const s = sim.current;
    s.v = LAUNCH_V;
    if (!s.raf) {
      s.last = performance.now();
      s.raf = requestAnimationFrame(step);
    }
  };

  return (
    <span ref={ref} className={styles.pokeball} onClick={launch}>
      <Image src="/pokeball.webp" alt="pokeball" width={size} height={size} />
    </span>
  );
}

"use client";

import { Fragment, useEffect, useRef, useState } from "react";
import styles from "./TrainerDashboard.module.css";
import Image from "next/image";
import Gravity, { MatterBody } from "./fancy/physics/gravity";
const TIPS = [
  "join #hackachu!",
  "pikapika",
  "hack club loves you",
  "your prizes are waiting....",
  "lock in"
];

const PROJECT_TYPES = ["Game", "Web", "CLI", "Hardware", "Other"];
const PIKAS = ["flying_pika.png", "magic_pika.png", "pika_with_cup.png"]
const PRIZES = [
  {
    name: "5 decks",
    hours: "+5 hours",
    img: "/prizes/decks.png",
    tilt: "tiltA",
  },
  {
    name: "awesome plushies",
    hours: "+10 hours",
    img: "/prizes/plushie.png",
    tilt: "tiltB",
  },
  {
    name: "watch or booster pack",
    hours: "+30 hours",
    img: "/prizes/booster.png",
    tilt: "tiltC",
  },
] as const;

export default function TrainerDashboard() {
  const [trainerName, setTrainerName] = useState("");
  const [tipIndex, setTipIndex] = useState(0);
  const [tipVisible, setTipVisible] = useState(true);
  const [panelOpen, setPanelOpen] = useState(false);
  const [shipped, setShipped] = useState(false);
  const [projName, setProjName] = useState("");
  const [projLink, setProjLink] = useState("");
  const [projDesc, setProjDesc] = useState("");
  const [activeTags, setActiveTags] = useState<string[]>([]);
  const panelRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const interval = setInterval(() => {
      setTipVisible(false);
      setTimeout(() => {
        setTipIndex((i) => (i + 1) % TIPS.length);
        setTipVisible(true);
      }, 250);
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  const togglePanel = () => {
    const opening = !panelOpen;
    setPanelOpen(opening);
    if (opening) {
      panelRef.current?.scrollIntoView({ behavior: "smooth", block: "center" });
    }
  };

  const toggleTag = (tag: string) => {
    setActiveTags((tags) =>
      tags.includes(tag) ? tags.filter((t) => t !== tag) : [...tags, tag]
    );
  };

  const resetForm = () => {
    setShipped(false);
    setProjName("");
    setProjLink("");
    setProjDesc("");
    setActiveTags([]);
  };

  return (
    <div className={styles.page}>
      <Gravity className={styles.gravityLayer}>
        {PIKAS.map((pika, i) => {
          return (
        <MatterBody
          x="20%"
          y="5%"
          matterBodyOptions={{
            friction: 0.5,
            restitution: 0.7,
            density: 0.001,
            isStatic: false,
          }}
          key={i}
        >
          <Image
            src={`/${pika}`}
            alt="pikachu"
            width={150}
            height={175}
          />
        </MatterBody>
          )
})}

      </Gravity>
      <div className={styles.wrap}>
        <div className={styles.nav}>
          <div className={styles.brand}>

            <div className={styles.brandText}>
              <span className={styles.brandEyebrow}>Hack Club · YSWS</span>
              <Image
              src="/hackachu.png"
              alt="Hackachu logo"
              width={200}
              height={48}
              className={styles.brandLogo}
              />
            </div>
          </div>

        </div>



        <div className={styles.dex}>


            <div className={styles.scanlines} />
            <div className={styles.screenGlow} />
            <div className={styles.greet}>
              WELCOME TRAINER,
              <br />
              <input
                className={styles.nameField}
                placeholder="YOU"
                maxLength={14}
                aria-label="Enter your trainer name"
                value={trainerName}
                onChange={(e) => setTrainerName(e.target.value)}
                style={
                  trainerName
                    ? { width: `${Math.max(3, trainerName.length + 1)}ch` }
                    : undefined
                }
              />
              .
            </div>
            <div
              className={styles.tip}
              style={{ opacity: tipVisible ? 1 : 0 }}
            >
              {TIPS[tipIndex]}
            </div>
            <a
              className={styles.hackatimeLink}
              href="https://hackatime.hackclub.com"
              target="_blank"
              rel="noopener"
            >
              &gt; connect your hackatime
            </a>

            <div className={styles.statGrid}>
              <div className={styles.stat}>
                <div className={styles.statNum}>0</div>
                <div className={styles.statLabel}>Projects Shipped</div>
              </div>
              <div className={styles.stat}>
                <div className={styles.statNum}>0h</div>
                <div className={styles.statLabel}>Hours Logged</div>
              </div>
              <div className={styles.stat}>
                <div className={styles.statNum}>I</div>
                <div className={styles.statLabel}>Trainer Rank</div>
              </div>

            </div>

        </div>

        <div className={styles.ctaRow}>
          <button className={styles.cta} onClick={togglePanel}>
            &gt; SUBMIT YOUR PROJECT
          </button>
        </div>

        <div
          ref={panelRef}
          className={`${styles.panel} ${panelOpen ? styles.panelOpen : ""}`}
        >
          <div className={styles.panelInner}>
            {!shipped ? (
              <div>
                <h3 className={styles.panelTitle}>Log your catch</h3>
                <p className={styles.panelSub}>
                  Tell us what you built. You can edit this after you ship.
                </p>
                <div className={styles.field}>
                  <label htmlFor="projName">Project name</label>
                  <input
                    id="projName"
                    type="text"
                    placeholder="e.g. Pixel Battle Sim"
                    value={projName}
                    onChange={(e) => setProjName(e.target.value)}
                  />
                </div>
                <div className={styles.field}>
                  <label htmlFor="projLink">Repo or demo link</label>
                  <input
                    id="projLink"
                    type="text"
                    placeholder="https://github.com/you/project"
                    value={projLink}
                    onChange={(e) => setProjLink(e.target.value)}
                  />
                </div>
                <div className={styles.field}>
                  <label htmlFor="projDesc">One-line description</label>
                  <textarea
                    id="projDesc"
                    placeholder="What does it do?"
                    value={projDesc}
                    onChange={(e) => setProjDesc(e.target.value)}
                  />
                </div>
                <div className={styles.field}>
                  <label>Project type</label>
                  <div className={styles.tagRow}>
                    {PROJECT_TYPES.map((tag) => (
                      <button
                        key={tag}
                        type="button"
                        className={`${styles.tag} ${
                          activeTags.includes(tag) ? styles.tagActive : ""
                        }`}
                        onClick={() => toggleTag(tag)}
                      >
                        {tag}
                      </button>
                    ))}
                  </div>
                </div>
                <button
                  className={styles.shipBtn}
                  onClick={() => setShipped(true)}
                >
                  SHIP IT &rarr;
                </button>
              </div>
            ) : (
              <div className={styles.success}>
                <div className={styles.successMark}>&#10003;</div>
                <h4>PROJECT SHIPPED!</h4>
                <p>
                  It&apos;s in the tall grass, awaiting review. We&apos;ll be
                  in touch soon.
                </p>
                <button className={styles.resetBtn} onClick={resetForm}>
                  Submit another
                </button>
              </div>
            )}
          </div>
        </div>

        <div className={styles.prizes}>
          <h2 className={styles.prizesTitle}>
            prizes<span className={styles.bang}>!!</span>
          </h2>
          <div className={styles.prizeRow}>
            {PRIZES.map((prize, i) => (
              <Fragment key={prize.name}>
                {i > 0 && <div className={styles.prizeArrow}>⮕</div>}
                <div className={styles.prize}>
                  {/* eslint-disable-next-line @next/next/no-img-element */}
                  <img
                    className={`${styles.prizeImg} ${styles[prize.tilt]}`}
                    src={prize.img}
                    alt={prize.name}
                  />
                  <div className={styles.prizeCaption}>
                    {prize.name}
                    <span className={styles.bang}>!</span>
                  </div>
                  <div className={styles.prizeHours}>{prize.hours}</div>
                </div>
              </Fragment>
            ))}
          </div>
          <div className={styles.prizeTotals}>(total hours: 5, 15, 40)</div>
        </div>

        <footer className={styles.footer}>
          hackachu · Hack Club YSWS · gotta ship &apos;em all
        </footer>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import Image from "next/image";
import Link from "next/link";
import styles from "./OnboardingWizard.module.css";

const SCREENS = ["welcome", "loot", "rules", "start"] as const;
type ScreenId = (typeof SCREENS)[number];

const SCREEN_LABELS: Record<ScreenId, string> = {
  welcome: "welcome",
  loot: "the loot",
  rules: "trainer rules",
  start: "ready to start",
};

const JOIN_URL = "https://auth.hackclub.com/join/hackachu";

const LOOT_TIERS = [
  {
    tag: "LVL 1",
    hours: "5 HOURS",
    desc: "Complete your first prototype and secure your deck foundations.",
    reward: "4X BOOSTER PACKS",
    img: "/prizes/decks.png",
  },
  {
    tag: "LVL 2",
    hours: "15 HOURS",
    desc: "Show true dedication to your RPG or card mechanics.",
    reward: "PLUSHIE OR MERCH",
    img: "/prizes/plushie.png",
  },
  {
    tag: "BOSS",
    hours: "40 HOURS",
    desc: "The ultimate grind. Legendary status achieved.",
    reward: "BOOSTER BOX OR SICK WATCH",
    img: "/prizes/booster.png",
  },
] as const;

const QUESTS = [
  {
    title: "QUEST 01: THE CREATOR",
    desc: "Build a Card Game or RPG (any theme!). Let your imagination run wild in the tall grass.",
    exp: 85,
  },
  {
    title: "QUEST 02: AI SYNERGY",
    desc: "AI is allowed, but keep it honest (no slop!). Use the machine, don't let it use you.",
    exp: 40,
  },
  {
    title: "QUEST 03: PURE CREATIVITY",
    desc: "Projects must be creative. We want to see your unique spark. No two trainers are the same.",
    exp: 65,
  },
] as const;

const BOOSTER_PACKS = [
  { name: "Trick or Trade", desc: "Halloween Special Edition" },
  { name: "Silver Tempest", desc: "Alolan Vulpix Art" },
  { name: "Surging Sparks", desc: "Electric Type Focus" },
] as const;

type WizardProps = {
  isButtonBigger: boolean;
}

export default function OnboardingWizard(props: WizardProps) {
  const [step, setStep] = useState<number | null>(null);
  const [menuOpen, setMenuOpen] = useState(false);

  const isOpen = step !== null;
  const isLast = step === SCREENS.length - 1;

  const open = () => {
    setStep(0);
    setMenuOpen(false);
  };

  const close = () => {
    setStep(null);
    setMenuOpen(false);
  };

  const goNext = () => {
    setStep((s) => (s === null || s >= SCREENS.length - 1 ? s : s + 1));
  };

  const goBack = () => {
    setStep((s) => {
      if (s === null) return s;
      if (s === 0) return null;
      return s - 1;
    });
  };

  const jumpTo = (index: number) => {
    setStep(index);
    setMenuOpen(false);
  };

  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.altKey && e.key.toLowerCase() === "s") {
        e.preventDefault();
        jumpTo(SCREENS.length - 1);
        return;
      }
      if (e.key.toLowerCase() === "a") {
        e.preventDefault();
        goNext();
      } else if (e.key.toLowerCase() === "b") {
        e.preventDefault();
        goBack();
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [isOpen]);

  return (
    <div className={styles.launcher}>
      <button type="button" className={props.isButtonBigger ? `${styles.triggerButton} ${styles.btnLarger}` : styles.triggerButton} onClick={open}>
        start adventure
      </button>
      <Link href="/dashboard" className={styles.loginLink}>
        already a trainer? login.
      </Link>

      {isOpen && (
        <div className={styles.overlay} role="dialog" aria-modal="true">
          <div className={styles.frame}>
            <div className={styles.topBar}>
              <span className={styles.topBarLogo}>HACKACHU</span>
              <button
                type="button"
                className={styles.closeButton}
                onClick={close}
                aria-label="close"
              >
                &times;
              </button>
            </div>

            <div className={styles.screenArea}>
              {step === 0 && <WelcomeScreen key="welcome" />}
              {step === 1 && <LootScreen key="loot" />}
              {step === 2 && <RulesScreen key="rules" />}
              {step === 3 && <StartScreen key="start" onStart={close} />}
            </div>

            <div className={styles.bottomBar}>
              <button
                type="button"
                className={styles.navButton}
                onClick={goBack}
              >
                &larr; back [b]
              </button>

              <div className={styles.menuWrap}>
                <button
                  type="button"
                  className={styles.menuButton}
                  onClick={() => setMenuOpen((v) => !v)}
                  aria-haspopup="true"
                  aria-expanded={menuOpen}
                >
                  menu
                </button>
                {menuOpen && (
                  <ul className={styles.menuList}>
                    {SCREENS.map((id, i) => (
                      <li key={id}>
                        <button
                          type="button"
                          className={styles.menuItem}
                          onClick={() => jumpTo(i)}
                          aria-current={step === i}
                        >
                          {SCREEN_LABELS[id]}
                        </button>
                      </li>
                    ))}
                  </ul>
                )}
              </div>

              {!isLast ? (
                <button
                  type="button"
                  className={styles.navButtonPrimary}
                  onClick={goNext}
                >
                  next [a] &rarr;
                </button>
              ) : (
                <span className={styles.navSpacer} />
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function WelcomeScreen() {
  return (
    <div className={styles.screen}>
      <span className={styles.badge}>the legendary you-ship-we-ship</span>
      <h2 className={styles.headline}>welcome to hackachu!</h2>

      <div className={styles.welcomeArt}>
        <Image
          src="/trainer.png"
          alt="pokemon trainer seen from behind"
          width={200}
          height={221}
        />
      </div>

      <div className={styles.dialogueBox}>
        <span className={styles.speakerTag}>prof. hacker</span>
        <p className={styles.dialogueText}>
          Welcome, Trainer! I&apos;m here to show you the rules of Hackachu, 
          the infamous Pokemon-themed YSWS. Ready to see what you can win?
        </p>
      </div>
    </div>
  );
}

function LootScreen() {
  return (
    <div className={`${styles.screen} ${styles.screenLoot}`}>
      <h2 className={styles.headlineBanner}>the loot</h2>

      <div className={styles.lootList}>
        {LOOT_TIERS.map((tier) => (
          <div className={styles.lootCard} key={tier.hours}>
            <span className={styles.lootTag}>{tier.tag}</span>
            <div className={styles.lootIcon}>
              <Image src={tier.img} alt={tier.reward} width={72} height={72} />
            </div>
            <p className={styles.lootHours}>{tier.hours}</p>
            <p className={styles.lootDesc}>{tier.desc}</p>
            <p className={styles.lootReward}>
              reward unlocked: <span>{tier.reward}</span>
            </p>
          </div>
        ))}
      </div>

      <div className={styles.systemMessage}>
        <strong>system message:</strong> the more you build, the better the
        loot! prizes are cumulative — submit the same project across
        milestones to stack rewards.
      </div>
    </div>
  );
}

function RulesScreen() {
  return (
    <div className={styles.screen}>
      <h2 className={styles.headlineBanner}>trainer rules</h2>

      <div className={styles.questList}>
        {QUESTS.map((quest) => (
          <div className={styles.questCard} key={quest.title}>
            <p className={styles.questTitle}>{quest.title}</p>
            <p className={styles.questDesc}>{quest.desc}</p>
            <div className={styles.expBar}>
              <div
                className={styles.expFill}
                style={{ width: `${quest.exp}%` }}
              />
            </div>
          </div>
        ))}
      </div>

      <div className={styles.prizeSummary}>
        <p>1st prize: 5h project = 4 booster packs.</p>
        <p>2nd prize: 15h cumulative = plushie/merch.</p>
        <p>3rd prize: 40h cumulative = booster box or sick watch.</p>
      </div>
    </div>
  );
}

function StartScreen({ onStart }: { onStart: () => void }) {
  return (
    <div className={styles.screen}>
      <h2 className={styles.headline}>ready to start?</h2>

      <div className={styles.incomingMessage}>
        <span className={styles.incomingTag}>incoming message</span>
        <p>
          Pick your path and start building. We can&apos;t wait to see what
          you create, adventurer!
        </p>
      </div>

      <a
        href={JOIN_URL}
        target="_blank"
        rel="noopener noreferrer"
        className={styles.startButton}
        onClick={onStart}
      >
        start adventure
      </a>

      <div className={styles.boosterPreview}>
        <div className={styles.boosterHeader}>
          <span>booster packs</span>
          <span className={styles.stockTag}>in stock</span>
        </div>
        <ul className={styles.boosterList}>
          {BOOSTER_PACKS.map((pack) => (
            <li key={pack.name} className={styles.boosterItem}>
              <span className={styles.boosterName}>{pack.name}</span>
              <span className={styles.boosterDesc}>{pack.desc}</span>
            </li>
          ))}
        </ul>
        <div className={styles.challengeTag}>
          current challenge: build an rpg or card game in 15h+
        </div>
      </div>
    </div>
  );
}

